            h(d,1,"2 系统架构设计");figure(d,"architecture.png","图 2-1 系统分层架构",15.5);p(d,"表示层只负责采集输入与展示结果；LibraryService 负责权限边界、输入校验和跨表事务；LibraryRepository 负责参数化 SQL 与结果映射；Database 负责连接、建表、提交和回滚。各层依赖方向单一，界面不直接访问数据库。");
            h(d,2,"2.1 技术选型");table(d,new String[]{"类别","技术","版本/方式","选择理由"},new String[][]{{"语言","Java","21 LTS","与课程方向一致，标准库完整"},{"桌面界面","Swing + FlatLaf","Java 21 / 3.5","跨平台、适合管理型桌面应用"},{"业务层","普通 Java 服务类","LibraryService","规则集中、便于自动测试"},{"数据访问","JDBC","预编译 SQL","直接、透明，符合选题要求"},{"演示数据库","H2","2.3 文件模式","零配置启动，MySQL 兼容语法"},{"部署数据库","MySQL","8.4 LTS","适合多客户端共享部署"},{"构建测试","Maven + JUnit","3.9 / 5.11","依赖、构建和回归测试标准化"},{"打包","Maven Shade","可执行 JAR","包含运行依赖，部署步骤少"}});
            h(d,2,"2.2 部署位置");table(d,new String[]{"层","部署位置","说明"},new String[][]{{"Swing 表示层","馆员或读者 Windows 客户端","应用窗口和本地 JVM"},{"服务层/DAO","与 Swing 同一 JVM","通过 Java 方法同步调用"},{"H2 数据库","单机 data 目录","课程演示与单用户使用"},{"MySQL 数据库","局域网数据库服务器或 Docker 容器","多客户端共享数据，端口 3306"}});
            h(d,1,"3 模块设计");figure(d,"modules.png","图 3-1 模块关系图",15.5);table(d,new String[]{"模块","职责","对应需求"},new String[][]{{"用户与权限","注册登录、资料、角色导航、借阅证状态","FR-01～FR-03"},{"图书管理","图书与分类增删改、馆藏数量约束","FR-04～FR-06"},{"馆藏查询","多字段模糊检索、库存展示","FR-07"},{"借阅管理","借阅、归还、续借、历史","FR-08～FR-11"},{"预约管理","排队、取消、到馆保留与提醒","FR-12～FR-13"},{"罚款管理","逾期计算、记录与缴费状态","FR-14～FR-15"},{"统计分析","库存概览、业务计数、热门排行","FR-16"}});h(d,2,"3.1 模块调用关系");p(d,"LoginFrame 和 LibraryFrame 调用 LibraryService；服务调用 LibraryRepository 的查询方法，复杂操作直接通过 Database.transaction 在同一连接中完成；Repository/Service 均使用 model.Models 中的不可变 record 作为数据载体。归还模块会依次调用库存恢复、罚款计算和预约唤醒逻辑，形成一个原子事务。");
