            h(d,1,"5 接口设计");p(d,"本项目是桌面应用，不提供对外 HTTP API。为满足接口统一识别，以下 URL 使用 library:// 内部 URI 表示界面命令；实际通信方式为同 JVM Java 方法调用。不得将这些 URI 误认为可通过浏览器访问的网络地址。");table(d,new String[]{"接口名","内部 URL","调用方法","功能"},new String[][]{{"用户登录","library://auth/login","login(username,password)","校验凭据并返回用户"},{"读者注册","library://users/register","register(...) ","创建读者账号"},{"馆藏查询","library://books/search","books(field,keyword)","按字段模糊检索"},{"新增图书","library://books/create","addBook(...) ","新增书目和库存"},{"办理借阅","library://loans/borrow","borrow(readerId,bookId)","校验规则并扣减库存"},{"办理归还","library://loans/return","returnBook(loanId)","恢复库存、罚款和唤醒预约"},{"续借","library://loans/renew","renew(loanId)","顺延应还日期"},{"预约","library://reservations/create","reserve(readerId,bookId)","创建排队或待取书记录"},{"缴费确认","library://fines/pay","payFine(fineId,readerId)","更新缴费状态"},{"统计","library://statistics/dashboard","dashboard()/rankings()","返回概览与排行"}});
            h(d,2,"5.1 通信方式");table(d,new String[]{"调用方","被调用方","方式","数据格式"},new String[][]{{"Swing 界面","LibraryService","进程内同步方法调用","Java 参数与 record"},{"LibraryService","LibraryRepository/Database","进程内同步方法调用","Java 参数、事务回调"},{"数据访问层","H2/MySQL","JDBC/TCP（MySQL）","预编译 SQL 与 ResultSet"}});
            h(d,1,"6 非功能需求实现方案");h(d,2,"6.1 安全");bullets(d,"PBKDF2-HMAC-SHA256 加盐存储密码，随机盐 16 字节、120000 次迭代。","SQL 全部使用 PreparedStatement 参数，避免把用户输入拼入 SQL。","按角色装配标签页，管理员命令不向读者显示；服务层再次验证读者与借阅证状态。","数据库账号使用最小权限，生产密码通过环境变量注入，不写入源码。");h(d,2,"6.2 异常处理");bullets(d,"输入错误抛出 IllegalArgumentException，在界面统一转换为中文对话框。","数据库异常转换为业务可读信息，唯一键或外键冲突不暴露堆栈。","跨表操作通过 Database.transaction 提交；任一步失败均回滚。","启动建表失败时阻止进入登录界面并显示原因。");h(d,2,"6.3 性能与一致性");bullets(d,"查询条件和关联键建立索引，检索使用数据库执行而非加载后过滤。","连接采用短事务、try-with-resources 及时释放；正式部署由 MySQL 服务器管理并发连接。","热门排行在数据库 GROUP BY 聚合，避免客户端逐条统计。","库存更新前使用行锁并在同一事务中校验，消除并发超借。","数据规模扩大后可在 Database 层替换 HikariCP 连接池，不改变上层接口；当前课程版不虚构未实现缓存。");
