            h(d,1,"2 系统总体设计");figure(d,"architecture.png","图 2-1 总体架构",15.5);table(d,new String[]{"包/类","职责"},new String[][]{{"LibraryApplication","设置外观、初始化数据库与服务、打开登录窗口"},{"ui.LoginFrame","登录和读者注册"},{"ui.LibraryFrame","按角色组织七个模块页面及交互"},{"service.LibraryService","业务校验、时间规则和事务编排"},{"db.LibraryRepository","基础 CRUD、查询、统计与对象映射"},{"db.Database","环境配置、连接、建表、事务提交回滚"},{"security.PasswordHasher","PBKDF2 密码派生和恒定时间校验"},{"model.Models","User、Book、Loan、Reservation、Fine 等不可变记录"}});
